import React, { useContext, useEffect } from 'react';
import PlanetsContext from '../contexts/PlanetsContext';

function Table() {
  const { loading, planets, getPlanets } = useContext(PlanetsContext);

  useEffect(() => () => getPlanets());

  return (
    <table>
      <thead>
        {
          planets[0].map((planet) => (
            <td>{Object.keys(planet)}</td>
          ))
        }
      </thead>
      {
        planets.map((planet) => (
          <tbody>
            <td>Olá</td>
            <td>Olá</td>
            <td>Olá</td>
          </tbody>
        ))
      }
    </table>
  );
}

export default Table;
